-- EBT data load into fleet `ebt` schema. Pilot FKs remapped onto public.pilots.
-- USER triggers disabled so derived-data triggers (carryover/evaluate/snapshot) do not
-- re-fire during bulk load; FK constraints stay enforced to reject any orphan pilot_id.
-- One-time EBT data load (not idempotent under db reset; prod is remote-only).
-- Pre-seed the 8 EBT-only (departed) pilots into fleet public.pilots as inactive,
-- reusing their EBT uuid so their training reports need no remap.
on conflict ("id") do nothing;

alter table "ebt"."aircraft_types" disable trigger user;
alter table "ebt"."check_types" disable trigger user;
alter table "ebt"."competencies" disable trigger user;
alter table "ebt"."grade_descriptors" disable trigger user;
alter table "ebt"."licences" disable trigger user;
alter table "ebt"."medicals" disable trigger user;
alter table "ebt"."observable_behaviours" disable trigger user;
alter table "ebt"."qualifications" disable trigger user;
alter table "ebt"."pilot_qualifications" disable trigger user;
alter table "ebt"."profiles" disable trigger user;
alter table "ebt"."record_retention" disable trigger user;
alter table "ebt"."training_reports" disable trigger user;
alter table "ebt"."report_carryover_focus" disable trigger user;
alter table "ebt"."report_competency_grades" disable trigger user;
alter table "ebt"."report_phases" disable trigger user;
alter table "ebt"."report_qualifications" disable trigger user;
alter table "ebt"."specialised_training" disable trigger user;
alter table "ebt"."report_specialised_training" disable trigger user;
alter table "ebt"."state_transitions" disable trigger user;
alter table "ebt"."user_roles" disable trigger user;
alter table "ebt"."remedial_requirements" disable trigger user;
alter table "ebt"."report_documents" disable trigger user;
alter table "ebt"."report_observed_behaviours" disable trigger user;
alter table "ebt"."report_signatures" disable trigger user;
alter table "ebt"."pilot_ext" disable trigger user;



